// Parseo y Enriquecimiento IA
// Tomamos directamente la información del flujo que entra a este nodo
const respuestaIA = $json;

let analisisIA = {};
try {
  // Extraemos el contenido que viene de Groq en la entrada inmediata
  const contenido = respuestaIA.choices?.[0]?.message?.content || '{}';

  // Limpiamos los bloques de código markdown por si la IA los puso (```json ... ```)
  const limpio = contenido.replace(/```json|```/g, '').trim();

  // Convertimos el texto en un JSON real con sus variables
  analisisIA = JSON.parse(limpio);
} catch(e) {
  // Plan de contingencia SOLO si el JSON de la IA viene verdaderamente roto
  analisisIA = {
    es_dano_real: true,
    categoria_ia: 'Daño Vial',
    prioridad_ia: 'moderada',
    score_severidad: 50,
    confianza: 50,
    palabras_peligro: [],
    diagnostico: 'Error al procesar el formato de la IA. Se requiere revisión manual en la malla vial.',
    accion_recomendada: 'Asignar inspección técnica física.',
    entidad_destino: 'Supervisores Alcaldía'
  };
}

// Determinar ruta de enrutamiento para tu Switch
const confianza = analisisIA.confianza || 50;
const prioridad = analisisIA.prioridad_ia || 'baja';
const esDanoReal = analisisIA.es_dano_real === true;

let rutamiento = '';
if (!esDanoReal || confianza < 0.35) {
  rutamiento = 'SPAM_SOSPECHOSO';
} else if (prioridad === 'critica' && confianza >= 70) {
  rutamiento = 'DESPACHO_INMEDIATO';
} else if (prioridad === 'moderada' || (prioridad === 'critica' && confianza < 70)) {
  rutamiento = 'REVISION_SUPERVISORES';
} else {
  rutamiento = 'COLA_NORMAL';
}

// Emojis de prioridad para Telegram
const emojiPrio = { critica: '🔴', moderada: '🟡', baja: '🟢' };

// Retornamos los datos combinados e independientes
return [{
  json: {
    ...$json, // Mantiene los datos que ya traías en la rama (nombre, teléfono, etc.)
    es_dano_real: esDanoReal,
    categoria_ia: analisisIA.categoria_ia || "Bache",
    prioridad_ia: prioridad,
    score_severidad: analisisIA.score_severidad || 50,
    confianza_ia: confianza,
    palabras_peligro: (analisisIA.palabras_peligro || []).join(', '),
    diagnostico: analisisIA.diagnostico || 'Análisis técnico de malla vial completado.',
    diagnostico_ia: analisisIA.diagnostico || 'Análisis técnico completado.',
    accion_recomendada: analisisIA.accion_recomendada || 'Programar cuadrilla de bacheo.',
    entidad_destino: analisisIA.entidad_destino || 'Cuadrilla Municipal',

    // Variables clave para tu Switch y Telegram
    rutamiento: rutamiento,
    emoji_prioridad: emojiPrio[prioridad] || '⚪',
    estado: rutamiento === 'SPAM_SOSPECHOSO' ? 'Pendiente Verificación' : 'En Asignación'
  }
}];

