// NODO: Parseo de comandos del bot

const update = $input.first().json;

if (update.message === undefined) {
  return []; // ignora si no es un mensaje normal
}

const msg = update.message || {};
const texto = (msg.text || '').trim();
const chatId = msg.chat?.id;
const nombreUsuario = msg.from?.first_name || 'Ciudadano';

// Detectar comando y parámetros
let comando = '';
let parametro = '';

if (texto.startsWith('/start')) {
  comando = 'start';

} else if (texto.startsWith('/consultar') || texto.startsWith('/estado')) {
  comando = 'consultar';
  const match = texto.match(/SCF-[A-Z0-9]+/i);
  parametro = match ? match[0].toUpperCase() : '';

} else if (texto.startsWith('/ayuda') || texto.startsWith('/help')) {
  comando = 'ayuda';

} else if (texto.startsWith('/reporte')) {
  comando = 'reporte';

} else {
  // Si el usuario escribe directamente un ticket ID
  const matchDirecto = texto.match(/SCF-[A-Z0-9]+/i);
  if (matchDirecto) {
    comando = 'consultar';
    parametro = matchDirecto[0].toUpperCase();
  } else {
    comando = 'desconocido';
  }
}

return [{
  json: {
    comando,
    parametro,
    chatId,
    nombreUsuario,
    mensajeOriginal: texto
  }
}];

const cmdData = $('⚙️ Parseo de Comandos Bot').first().json;
const filas = $input.all();

if (!filas || filas.length === 0 || !filas[0].json['TicketID']) {
  return [{ json: {
    chatId: cmdData.chatId,
    texto: `❌ *Ticket no encontrado*\n\nNo encontré el ticket \`${cmdData.parametro}\`.\n\nVerifica que el ID sea correcto (formato: SCF-XXXXXX) y vuelve a intentarlo.`
  }}];
}

const ticket = filas[0].json;

const estadoEmoji = {
  'En Asignación': '🔄',
  'En Proceso': '🔧',
  'Solucionado': '✅',
  'Pendiente Verificación': '⚠️'
};
const emojiEstado = estadoEmoji[ticket['Estado']] || '🔄';

const prioemoji = {
  'critica': '🔴',
  'moderada': '🟡',
  'baja': '🟢'
};
const emojiPrio = prioemoji[(ticket['Prioridad'] || '').toLowerCase()] || '⚪';

return [{ json: {
  chatId: cmdData.chatId,
  texto: `${emojiEstado} *Estado de tu Reporte*\n\n🎫 Ticket: \`${ticket['TicketID']}\`\n${emojiEstado} *Estado:* ${ticket['Estado'] || 'Por asignar'}\n${emojiPrio} *Prioridad:* ${ticket['Prioridad'] || 'Por definir'}\n\n🏷️ *Tipo:* ${ticket['Categoria'] || 'Sin categoría'}\n📍 *Ubicación:* ${ticket['Direccion Real'] || 'No especificada'}\n\nPara más información, contacta a SmartCity-Fix.`
}}];

